"""
mkt-original layer — Acts chapters 4–6
Run: python3 scripts/zc-original-acts-4-6.py
Output: data/commentary/mkt-original/acts.json

Key decisions:
- Acts 4:25 pais ('servant/child') applied to both David and Jesus connects the Davidic
  covenant and the Servant Songs; rendered 'servant' not 'child' for theological clarity
- Acts 5:1-2 nosphizomai ('misappropriate') echoes Josh 7:1 (Achan); Luke almost certainly
  intends the typological resonance — the community's first internal crisis mirrors Israel's
- Acts 5:11 'ekklesia' — first occurrence in Acts; the community now has its name
- Acts 5:30 'kremesantes epi xylou' (hanging on a tree) echoes Deut 21:23; Luke signals
  the cross as covenant curse (cf. Gal 3:13) without citing it explicitly
- Acts 5:31 'archegos kai soter' continues the 3:15 archegos Christology; pioneer/savior pair
- Acts 6:1 Hellenistai/Hebraioi — Greek-speaking vs Aramaic-speaking Jews within the church
- Acts 6:9 Libertinos — likely Roman freedmen of Jewish descent with their own Jerusalem synagogue
- Existing entries: ch4 v12, v32; ch5 v29 — merge_comm will skip these
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: add entries without overwriting existing ones
    # CHANGE? If schema changes, update here; existing ch4 v12/v32, ch5 v29 must be preserved
    # VERIFY: after run, ch4/ch5/ch6 in mkt-original/acts.json have all verse keys
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "4": {
    "1": "<p><strong>strategos tou hierou</strong> (<em>stratēgos tou hierou</em>, 'captain of the temple') was the second-ranking authority in Jerusalem after the high priest, responsible for temple security and public order. His appearance alongside priests and Sadducees signals the full weight of the Jerusalem establishment mobilizing against the apostles; this is not a minor local altercation but an institutional response.</p>",

    "2": "<p><strong>kataggellein en to Iesou ten anastasin</strong> ('proclaiming in Jesus the resurrection from the dead'): the preposition <em>en</em> is significant — the resurrection is proclaimed <em>in</em> Jesus, using him as the concrete instance that validates the resurrection reality. The Sadducees denied resurrection on principle; the apostles were not preaching a general philosophical resurrection but pointing to a specific man who had risen and thereby demonstrated the doctrine in historical fact.</p>",

    "3": "<p><strong>eis teresin</strong> (<em>eis tērēsin</em>, 'into custody'): a technical legal term for preventive detention pending investigation, distinct from punitive imprisonment. Luke's precision — 'because it was already evening' — notes that the timing prevented immediate trial; Sanhedrin procedure required daylight hearings. The detail is historically credible and marks Luke's familiarity with Jewish juridical practice.</p>",

    "4": "<p><strong>arithmos ton andron</strong> ('the number of the men'): Luke counts men (<em>andrōn</em>) specifically, following Jewish convention that tallied males for quorum and membership purposes. The number 5,000 represents a significant fraction of Jerusalem's population; the community has grown from 120 (1:15) to 3,000 (2:41) to 5,000 in rapid succession. Luke structures his growth notices as theological progress reports, not merely sociological data.</p>",

    "5": "<p><strong>archontes kai presbyteroi kai grammateis</strong> ('rulers and elders and scribes'): the three constituent groups of the Sanhedrin, the supreme Jewish council of 71 members that held judicial, legislative, and administrative authority. Luke uses this tripartite formula deliberately — the identical body that condemned Jesus is now summoned against his apostles. The narrative parallelism is intentional: the disciples face the same tribunal that their Lord faced.</p>",

    "6": "<p>Annas had been deposed as high priest by the Romans in AD 15 but retained enormous personal authority and the loyalty of the priestly aristocracy; his sons and son-in-law Caiaphas (still serving as high priest, cf. Luke 3:2; John 18:13) constituted a dynastic priestly faction. Luke's list of names signals historical specificity and suggests access to accurate sources about Jerusalem's power structure in the 30s.</p>",

    "7": "<p><strong>en poia dynamei e en poio onomati</strong> ('by what power or by what name'): the two questions are functionally equivalent in Jewish thought — the <em>shem</em> (name) was the concentrated reality and authority of a person, so action performed 'in a name' was action powered by that name's authority. The Sanhedrin wants to know whose delegated power the apostles have invoked, assuming some authorized intermediary. Peter's answer (v.10) uses precisely this framework but names a name they did not authorize.</p>",

    "8": "<p><strong>plesthe Pneumatos Hagiou</strong> (<em>plēstheis Pneumatos Hagiou</em>, 'filled with the Holy Spirit'): Luke's aorist passive marks this as a fresh, specific endowment for this occasion, not simply the ongoing condition of 2:4. Peter before the Sanhedrin enacts the promise of Luke 12:11-12 ('when they bring you before the synagogues and the rulers and the authorities, do not be anxious about how you should defend yourself... the Holy Spirit will teach you in that very hour what you ought to say'). The fulfillment is immediate and precise.</p>",

    "9": "<p><strong>euergesia</strong> (<em>euergesia</em>, 'good deed/act of benefaction'): Peter uses the standard Hellenistic vocabulary of public benefaction — the <em>euergetēs</em> (benefactor) was a patron whose good deeds benefited the city. By framing the healing as a <em>euergesia</em>, Peter subtly argues within the council's own civic framework: they are prosecuting a case of public benefit, not public harm. Luke's Greek shows Peter adapting register to his audience.</p>",

    "10": "<p><strong>en tō onomati Iēsou Christou tou Nazōraiou</strong> ('in the name of Jesus Christ the Nazarene'): the full messianic title with geographic qualifier. <em>Nazōraios</em> in Acts (2:22; 3:6; 4:10; 6:14; 22:8; 24:5; 26:9) maintains continuity with the ministry of Jesus of Nazareth against any tendency to abstract the risen Christ from his historical particularity. The name is simultaneously claim, invocation, and challenge: the council crucified this man, and God raised him.</p>",

    "11": "<p><strong>ho lithos ho exouthenetheis ... eis kephalēn gōnias</strong> (Ps 118:22): Peter applies the psalm directly to the council. <em>Kephalē gōnias</em> ('head of corner') is disputed — either the capstone completing an arch or the massive foundation stone at the base of a corner. Either meaning emphasizes indispensability: the stone the builders discarded is the one on which the whole structure depends. The quotation reframes the crucifixion as a builder's error that God corrected by resurrection-exaltation.</p>",

    "13": "<p><strong>agrammatos kai idiōtai</strong> ('unlettered and untrained'): <em>agrammatos</em> means lacking formal scribal education — the ability to read, interpret, and teach Torah in the scribal tradition. <em>Idiōtēs</em> is a layperson relative to a professional; in rhetorical contexts it means an untrained speaker vs a trained orator. The council's astonishment is that these men argue with force and coherence despite lacking the credentials that would normally explain such performance. Their only explanation is the training of Jesus (v.13b).</p>",

    "14": "<p><strong>theōrountes</strong> (<em>theōrountes</em>, 'seeing/beholding') is Luke's vocabulary for significant observation — more than mere glancing. The healed man's physical presence as a living exhibit makes refutation impossible; any argument the council might construct against the healing's reality is undercut by the 40-year-old man standing with his healed limbs on display. Luke notes the council's rhetorical problem: evidence stood in front of them.</p>",

    "15": "<p>The Sanhedrin's private deliberation (<em>keleusantes autous exō tou synedriou apelthein</em>) is a narrative concession to realism: Luke acknowledges he cannot have attended. The detail suggests either that a participant later disclosed the discussion (a sympathizer like Nicodemus or the Gamaliel of ch.5) or that the substance of the decision became known from its public outcome. Luke does not claim omniscience; he reports what became known.</p>",

    "16": "<p><strong>semeion gnōston</strong> ('notable sign'): the council's internal framing is revealing — they accept the sign's factual reality (<em>gnōston</em>, 'known/evident') but treat it as a political problem rather than a theological datum. This is the pattern Luke identifies as culpable unbelief: those with sufficient evidence who choose political calculation over truth. Their question 'what shall we do?' (v.16) echoes the crowd's question in 2:37, but leads to suppression rather than repentance.</p>",

    "17": "<p><strong>apeilē</strong> (<em>apeilē</em>, 'threat') + <strong>me phthenggesthai</strong> ('not to utter'): <em>phthenggesthai</em> is a significant word — used in LXX for prophetic utterance (Mic 5:12; Ezek 13:9; Ps 19:3) and by Luke in 2:4 and 2:14 for inspired Pentecost speech. The council's command to stop <em>phthenggesthai</em> is unknowingly a command to cease prophetic proclamation. Luke's word choice signals that the apostles' speech has a higher category — suppressing it is suppressing prophecy.</p>",

    "18": "<p><strong>kathōlos</strong> ('at all/entirely'): the absolute prohibition — not merely reduced teaching but a complete ban on speaking or teaching in this name. The council's overreach establishes the conflict of loyalties that v.19-20 will address. The command is total, which is why Peter's answer (<em>dei</em>, 'it is necessary') must be equally total: divine necessity overrides human prohibition.</p>",

    "19": "<p><strong>ei dikaion estin</strong> ('whether it is just'): Peter invokes the council's own standards. In Greek political philosophy and Jewish legal tradition, obedience to unjust commands was not obligatory. Peter does not refuse outright but poses the logical prior question — is this command lawful? He then appeals to God's court, leaving the evaluation to the audience. The argument has Socratic precedent (Plato, <em>Apology</em> 29D) and Jewish martyr tradition (2 Macc 7).</p>",

    "20": "<p><strong>ou dynametha</strong> ('we are not able'): the phrase carries both epistemic force (we cannot deny what we have seen) and volitional force (we cannot choose to keep silent about it). The apostles do not merely say 'we will not' but 'we cannot' — their witness is constrained by what they have directly seen and heard (<em>ha eidamen kai ēkousamen</em>). Eyewitness testimony is their irreducible ground; it cannot be surrendered by command.</p>",

    "21": "<p><strong>kolasosin</strong> (<em>kolasōsin</em>, 'to punish/chastise'): the council wanted to punish the apostles but was constrained by public opinion (<em>ton laon</em>). Luke's narrative repeatedly notes this popular-political check on official action (cf. 5:26; Luke 20:6; 22:2). <em>Doxazon</em> ('glorifying') — the people's response to the healing is praise for God, precisely what the council cannot argue against without alienating the population they need.</p>",

    "22": "<p>Luke's parenthetical note that the healed man was over forty years old functions as evidentiary detail: the duration of the disability eliminates the possibility of spontaneous healing or misdiagnosis. The Sanhedrin cannot argue statistical coincidence against a man congenitally lame from birth (3:2) for over four decades. Luke's attention to ages throughout Acts (the man here; Paul in various passages) reflects Hellenistic historical writing's use of concrete detail to establish credibility.</p>",

    "23": "<p><strong>tous idious</strong> ('their own people'): the phrase signals communal identity — the apostles' primary accountability is to their own community rather than the council. Luke's use of <em>idios</em> in Acts (2:6; 4:23, 32; 24:24; 25:19) consistently marks belonging. The community gathers to hear the report and turns immediately to prayer, modeling the pattern of apostolic community: shared experience leads to corporate prayer leads to renewed mission.</p>",

    "24": "<p><strong>Despota</strong> (<em>Despota</em>, 'Sovereign Master'): less frequent than <em>Kyrios</em>, this address emphasizes absolute sovereignty and ownership — the relationship between a master and his household. The prayer opens by anchoring God's authority in creation (citing Ps 146:6 / Exod 20:11) before petitioning him to act in history. The logic is implicit: if you made all things, you govern all things; therefore the council's opposition is within your sovereign management.</p>",

    "25": "<p><strong>pais</strong> (<em>pais</em>, 'servant/child') is applied to David (v.25) and Jesus (v.27, 30). The word bridges the Davidic covenant and the Servant Songs — it can mean both 'son' (in the sense of Ps 2) and 'servant' (in the sense of Isa 52-53). Luke's consistent application of <em>pais</em> to Jesus (3:13, 26; 4:27, 30) is his preferred Servant-Christology term in these early speeches, keeping the dual resonance of royal son and suffering servant in view simultaneously.</p>",

    "26": "<p>The community's prayer cites Ps 2:1-2 (<em>parestathesan hoi basileis tēs gēs kai hoi archontes synēchthēsan epi to auto kata tou kyriou kai kata tou christou autou</em>) and then immediately identifies its historical referent in vv.27-28. This is the apostolic hermeneutic in concentrated form: take a psalm, identify its referent as Christ, then read the psalm's terms as the grid for reading history. Herod and Pilate are the 'kings and rulers' of Ps 2; the Gentiles and Israel are the nations; the conspiracy was the Passion.</p>",

    "27": "<p><strong>aleipsas</strong> (<em>hōn echrisen</em>, 'whom you anointed'): the verb <em>chriō</em> (to anoint) links Jesus directly to the title <em>Christos</em> (the Anointed One, Messiah). The anointing referred to may be the Spirit's descent at baptism (Luke 3:22; 4:18 — 'the Spirit of the Lord is upon me because he has anointed me'), the incarnation itself, or the resurrection-exaltation. The prayer assumes that Ps 2's royal anointing has been applied to Jesus, making every subsequent opposition to Jesus a fulfillment of the psalm's scenario.</p>",

    "28": "<p><strong>proōrisen</strong> (<em>proōrisen</em>, 'foreordained/predetermined'): Luke's strongest statement of divine determinism in Acts, alongside 2:23 ('delivered up by the definite plan and foreknowledge of God'). The council's decision, Pilate's capitulation, Herod's involvement — all were 'predetermined by your hand and your counsel' (<em>tē sē boulē</em>). This is not fatalism that removes human responsibility (the actors are still culpable) but providence that guarantees divine purpose through human free action. The tension is held without resolution, as in the OT wisdom tradition.</p>",

    "29": "<p><strong>meta parresias pases</strong> (<em>meta parrēsias pasēs</em>, 'with all boldness'): <em>parrēsia</em> (boldness, freedom of speech) is a key term in Acts (2:29; 4:13, 29, 31; 9:27, 28; 13:46; 14:3; 18:26; 19:8; 26:26; 28:31). In Hellenistic political philosophy it was the freedom of a citizen to speak freely before the assembly; in Acts it is the Spirit-given freedom to speak the gospel before any audience, regardless of threat. The community does not pray for deliverance from opposition but for boldness to continue speaking within it.</p>",

    "30": "<p><strong>en tō ekteinein se ten cheira sou</strong> ('as you stretch out your hand'): the divine hand as agent of miraculous power is OT idiom (Exod 3:20; 9:15; Deut 26:8; Ps 138:7). The prayer frames the apostles' healing ministry as God's own hand working through them — they are instruments, not autonomous agents. <strong>sēmeia kai terata</strong> ('signs and wonders') is the standard OT theophany-vocabulary (Exod 7:3; Deut 4:34; 6:22; 7:19; Ps 78:43) now applied to apostolic ministry.</p>",

    "31": "<p><strong>esaleuthē ho topos</strong> ('the place was shaken'): physical phenomena marking divine response to prayer echoes OT theophanies (Exod 19:18 — Sinai shaking at the divine descent; Isa 6:4 — the temple threshold shaking at the divine glory). The community is refilled with the Spirit (<em>eplēsthēsan hapantes</em>) — Luke does not treat Pentecost as a once-for-all endowment never needing renewal. The Spirit is continuously given in fresh measure for fresh occasions of witness.</p>",

    "33": "<p><strong>megale charis en epi pantas autous</strong> ('great grace was upon them all'): <em>charis</em> in Luke-Acts carries both divine favor (God's gracious disposition) and the concrete expression of that favor in community life. The phrase functions as a summary theological assessment of the community: their unity, generosity, and witness are the marks of divine charis resting on them. The construction echoes similar summaries in Luke's Gospel (Luke 2:40 of the child Jesus — 'the grace of God was upon him').</p>",

    "34": "<p><strong>ouk en endees tis en autois</strong> ('there was not a needy person among them'): the exact fulfillment of Deut 15:4 LXX ('there shall be no poor among you') — a striking echo that Luke almost certainly intends. The Deuteronomic ideal of a community without poverty, which Israel never fully realized in the land, is enacted in the Jerusalem church. Luke presents the community's economic life as the actualization of covenantal promise.</p>",

    "35": "<p><strong>para tous podas ton apostolōn</strong> ('at the feet of the apostles'): the gesture of placing something at someone's feet is a posture of voluntary submission and recognition of authority. The Twelve receive and administer the common fund — not by compulsion but by communal agreement. The prepositional phrase establishes apostolic authority as the structural center of the community's economic life, a detail that prepares for the crisis of ch.5 and the administrative expansion of ch.6.</p>",

    "36": "<p><strong>pais paraklēseōs</strong> (<em>huios paraklēseōs</em>, 'son of encouragement'): the Semitic <em>bar-</em> construction (son of X = characterized by X) indicates that Barnabas was known as an encourager — one who exhorted, consoled, and strengthened others. <em>Paraklēsis</em> is the same word-family as <em>paraklētos</em> (the Advocate/Spirit, John 14:16); here it identifies a human ministry of comfort and exhortation. Luke introduces Barnabas here because he will become Paul's first significant partner in mission (9:27; 11:22-30; 13-15).</p>",

    "37": "<p>The Barnabas episode (<em>hyparchontos autō agrou</em>, 'having a field') functions as the positive exemplar that immediately precedes the Ananias and Sapphira counter-example of ch.5. Luke's narrative pairs the genuine and the counterfeit: Barnabas's wholehearted surrender of the proceeds is the model; Ananias and Sapphira's deceptive partial surrender is the perversion. The field/land vocabulary links both narratives, making the contrast structural.</p>"
  },

  "5": {
    "1": "<p><strong>Hananias</strong> (<em>Ananias</em>) and <strong>Sappheira</strong> (<em>Sapphira</em>) — both Hebrew names. Luke records their names, unlike many anonymous figures in Acts, signaling that this event had historical specificity in community memory. The narrative introduces the community's first internal moral failure — not external persecution but internal deception. The threat to the church from within is as grave as the threat from the Sanhedrin without.</p>",

    "2": "<p><strong>enosphisato</strong> (<em>enosphisato</em>, 'he embezzled/misappropriated'): the same word used in the LXX of Josh 7:1 (<em>enosphisato</em>) for Achan's misappropriation of devoted things from Jericho's spoils. The resonance is almost certainly deliberate: Achan's sin introduced covenant violation into Israel immediately after entry into the land; Ananias's sin introduces covenant violation into the church immediately after Pentecost. Both disrupted a new covenantal beginning; both were exposed by divine revelation.</p>",

    "3": "<p><strong>eplērōsen ho Satanas tēn kardian sou</strong> ('Satan has filled your heart'): the contrast with Spirit-filling is explicit — Pentecost filled the community with the Holy Spirit (2:4; 4:31); Ananias has been filled by Satan. The same verb (<em>plēroō</em>), the same location (the heart), the opposite agent and direction. Deception is not merely moral failure but a form of demonic collaboration. <strong>pseudesthai</strong> ('to lie'): lying to the Spirit is lying to God (v.4) — Peter's equation affirms the Spirit's full divinity.</p>",

    "4": "<p><strong>ouchi menon soi emenen kai prathen en sē exousia hypērchen</strong>: Peter's double assertion — while it remained unsold it was yours; after it was sold the proceeds were at your disposal — confirms that the Jerusalem community did not require communal property. The sin was not keeping the money but lying about having given it all. The voluntary nature of the sharing is essential to understanding the community's economic ethic: it was genuine gift, not tax.</p>",

    "5": "<p><strong>ekpneō</strong> (<em>ekpneusas</em>, 'he breathed his last/expired'): Luke uses clinical vocabulary — the same verb he uses for Jesus's death in Luke 23:46. The sudden death is not reported as miraculous in the ordinary sense; it is a divine judicial act. <strong>phobos megas</strong> ('great fear'): the fear that follows Ananias's death and then Sapphira's (v.11) is not terror but awe — the recognition that the community inhabits a space where divine holiness is operative and cannot be trifled with.</p>",

    "6": "<p><strong>synesteilantes</strong> (<em>systeilan</em>, 'wrapping/shrouding'): the young men (hoi neōteroi) act immediately without deliberation. The speed of the burial is consistent with Jewish practice (burial before sundown) and adds to the solemnity of the narrative — there is no interval for appeal or reconsideration. Luke's brevity here reflects the event's shock value in community memory.</p>",

    "7": "<p><strong>hōs hōrōn triōn diastēma</strong> ('after about three hours'): Luke's chronological precision creates dramatic irony — Sapphira has been going about her day unaware of her husband's death, and comes in after three hours to face Peter's question. The interval is long enough that the burial is complete but short enough that she still expects to reunite with her husband. Luke's narrative technique here produces the same tension as a trial scene.</p>",

    "8": "<p>Peter's question — <strong>tosoutou to chorion apedosthe</strong> ('did you sell the land for so much?') — is not a request for information but a forensic trap. Peter already knows the answer (through the Spirit's revelation, v.3). He gives Sapphira the opportunity to tell the truth; her confirmation of the lie is her own self-condemnation. The interrogation follows the pattern of divine testing in the OT (Gen 3:9-13; 4:9), where God questions not from ignorance but to expose what the heart already holds.</p>",

    "9": "<p><strong>peirazo</strong> (<em>peirasai</em>, 'to test'): Peter's charge — 'why did you conspire to test the Spirit of the Lord?' — places the Ananias and Sapphira incident in the category of Israel's wilderness murmuring and testing of God (Exod 17:2, 7; Ps 78:18, 56; 95:9; 106:14). Testing the Spirit of the Lord was the characteristic sin of the wilderness generation that died before reaching the land; the same pattern is now enacted at the beginning of the new covenant community.</p>",

    "10": "<p>Sapphira's immediate death (<em>epesen de parachrēma pros tous podas autou kai exepsyxen</em>, 'immediately she fell at his feet and expired') parallels her husband's death structurally. Luke notes both that she fell 'at his feet' (cf. the apostles' feet as locus of authority in 4:35, 37) and that the same young men came and buried her beside her husband. The symmetry is deliberate: the couple acted together in deception; they died together in judgment.</p>",

    "11": "<p><strong>ekklēsia</strong> (<em>ekklēsia</em>): this is the first unambiguous use of <em>ekklēsia</em> in Acts (the word appears in variant readings at 2:47 but is textually uncertain there). The word meant the civic assembly of citizens in Hellenistic cities but carried OT weight as the LXX translation of <em>qahal</em> (the assembly of Israel). Luke's application of <em>ekklēsia</em> to the messianic community identifies them as the renewed assembly of Israel, the covenant people gathered in the new exodus.</p>",

    "12": "<p><strong>sēmeia kai terata polla</strong> ('many signs and wonders'): the third summary of apostolic miracles (2:43; 4:30; 5:12). Luke's repetition establishes a rhythm: the word is proclaimed, the Spirit acts in power, the community grows, opposition arises. <strong>Stoa tou Solomōnos</strong> ('Solomon's Porch'): the eastern colonnade of the temple complex (cf. John 10:23); the apostles used a public, recognizable location, not a private house, for teaching.</p>",

    "13": "<p><strong>oudeis etolma kollasthai autois</strong> ('no one else dared to join them'): <em>kollaō</em> (attach oneself, join closely) is the same word used for the community's adherence to one another (v.36 in a different context). The awe following the Ananias and Sapphira judgment created a selective barrier: casual seekers kept their distance while those who genuinely believed were added (v.14). Luke presents holy fear as a purifying filter on membership, not a deterrent to genuine conversion.</p>",

    "14": "<p><strong>prosetithento pisteuontes tō kyriō</strong> ('believers were added to the Lord'): the community's growth is consistently described as addition to <em>the Lord</em> (2:47; 5:14; 11:24) — not merely to the group — signaling that the community's center of gravity is personal relationship to the risen Christ. The explicit mention of both men and women (<em>andrōn te kai gynaikōn</em>) after Pentecost's inclusive outpouring (Joel 2:28-29) is Luke's narrative confirmation that gender is not a barrier to membership.</p>",

    "15": "<p><strong>hina erchomenou Petrou kan hē skia episkiasē</strong> ('so that even Peter's shadow might fall on some of them'): Luke does not affirm whether the shadow healings worked; he reports the crowd's expectation. The pattern echoes the healings through Paul's handkerchiefs and aprons in 19:12 — the divine power operating through physical media associated with the apostle. Both passages reflect popular faith that God worked through proximity to his agents, as he worked through Elisha's bones (2 Kgs 13:21).</p>",

    "16": "<p><strong>ochloi</strong> ('crowds'): the geographic expansion — from Jerusalem to surrounding towns — follows the Acts 1:8 pattern. The mission radiates outward naturally, not yet through intentional missionary strategy but through the reputation of the apostolic ministry. <strong>ochloumenous hypo pneumatōn akathartōn</strong> ('tormented by unclean spirits'): Luke's healing summaries always include exorcism alongside physical healing, maintaining the integrated Synoptic pattern of Jesus's ministry.</p>",

    "17": "<p><strong>anastropheis zēlou</strong> (<em>plēsthēnai zēlou</em>, 'filled with jealousy'): the same term — filled (<em>plēroō</em>) — used for Spirit-filling now describes the jealousy that animates the high priest. The bitter irony is structural: the high priest, who should lead the community in discerning God's work, is filled with the anti-Spirit of jealousy while the apostles are filled with the Holy Spirit. Luke's vocabulary creates a pointed comparison.</p>",

    "18": "<p><strong>epebalan tas cheiras</strong> ('laid their hands on'): the hostile laying on of hands contrasts with the community's gesture of commissioning and blessing (6:6; 13:3). The same physical act carries opposite meanings depending on the agent and intention. Luke's narrative sophistication regularly exploits these lexical contrasts to highlight the divided response to the apostolic mission.</p>",

    "19": "<p><strong>angelos de Kyriou</strong> ('an angel of the Lord'): the divine rescue pattern — imprisonment followed by miraculous release — is established here (cf. 12:7-11; 16:26). Luke presents the angel as divine agent, not metaphor; the detail about opening locked doors (v.23) makes the miraculous nature explicit. The angel's message is not merely release but re-commission: 'go and speak in the temple all the words of this life' (v.20).</p>",

    "20": "<p><strong>ta rhēmata tēs zōēs tautēs</strong> ('the words of this life'): the phrase 'this life' (<em>tautēs</em>) refers to the resurrection life — the eschatological life inaugurated by Christ's resurrection that is now available and is the content of the apostolic proclamation. The command returns the apostles immediately to the place of danger (the temple courts) rather than directing them to safety — witness continues in the theater of opposition.</p>",

    "21": "<p><strong>gerousion</strong> (<em>gerousian</em>): a near-synonym for the Sanhedrin, literally 'assembly of elders' (cf. the Hebrew <em>ziqnei Israel</em>). Luke's doubling — 'Sanhedrin and all the senate of the sons of Israel' — may indicate the full formal convening of all associated leadership bodies, or may be literary intensification to indicate the comprehensive nature of the official response. Either way, it signals the maximum institutional weight arrayed against the apostles.</p>",

    "22": "<p>The officers' discovery of the empty prison — <em>euron autous ou en tē phylakē</em> ('they did not find them in the prison') — is narrated without explanation at this point; Luke delays the angelic rescue account structurally (it is implied but not yet stated). The sequence creates a moment of dramatic suspense: the officials know the prison is secure (v.23) but the apostles are absent. The resolution requires the theophanic framework of angelic intervention.</p>",

    "23": "<p><strong>meta pasēs aspaleias kekleismenon</strong> ('locked with all security'): the guards' report emphasizes the physical security of the prison — doors locked, guards in place — to make the angelic release undeniable. Luke's detail serves an apologetic function: the release cannot be explained by bribery, guard negligence, or official connivance. The only available explanation is the miraculous intervention that the narrative has already identified (v.19).</p>",

    "24": "<p><strong>diēporoun peri autōn</strong> ('they were perplexed about them'): <em>diaporeō</em> (be thoroughly perplexed) is Luke's term for the cognitive disruption that miraculous events produce in observers (cf. Luke 9:7; Acts 2:12; 10:17). The officials cannot fit the data into their interpretive framework; the prison is secure but empty. Luke presents such perplexity as the appropriate preliminary to genuine inquiry — it opens the question that only the gospel can answer.</p>",

    "25": "<p>The report — 'the men you put in prison are standing in the temple courts teaching the people' — is narrated at maximum dramatic compression. Luke does not explain the officers' emotional response; it is implied by the contrast: they locked the apostles away, and now find them publicly doing the exact thing they were imprisoned for doing. The apostles' obedience to the angel's command (v.20) is confirmed by the report.</p>",

    "26": "<p><strong>ou meta bias</strong> ('without force/violence'): the captain's restraint reflects the same popular constraint noted in 4:21 — the authorities cannot act against the apostles openly without risking popular backlash. Luke's 'fear of being stoned' is a recognition that the crowd's sympathy for the apostles served as providential protection. The same dynamic will reappear in ch.21-26, where Paul navigates Roman and Jewish legal systems partly because of the crowd's divided loyalties.</p>",

    "27": "<p>The second appearance before the Sanhedrin parallels and escalates the first (ch.4). The formal setting — <em>estēsan en tō synedriō</em> ('they stood them in the Sanhedrin') — and the high priest's interrogation (<em>eperōtēsen autous</em>) reprises the earlier tribunal scene. Luke's narrative is building a pattern: the apostles are repeatedly arrested, repeatedly released, and repeatedly more bold, enacting the Ps 2 scenario of opposition that cannot ultimately prevail.</p>",

    "28": "<p><strong>eplērōkate tēn Ierousalēm tēs didachēs hymōn</strong> ('you have filled Jerusalem with your teaching'): the accusation ironically confirms what Luke has been narrating — the gospel has indeed filled Jerusalem. The council's complaint is Luke's progress report. <strong>epagagein eph' hēmas to haima tou anthrōpou toutou</strong> ('bring this man's blood upon us'): an implicit acknowledgment of guilt; they recognize that the apostles are accusing them of Jesus's death, which they cannot flatly deny.</p>",

    "30": "<p><strong>kremesantes epi xylou</strong> (<em>kremasantes epi xylou</em>, 'hanging on a tree'): the phrase evokes Deut 21:23 ('anyone who is hung on a pole is under God's curse'). Paul makes the connection explicit in Gal 3:13 ('Christ redeemed us from the curse of the law by becoming a curse for us — for it is written: Cursed is everyone who is hung on a tree'). Luke's language here implies the same Deuteronomic background: Jesus bore the covenant curse, which is why God raised him from the dead rather than leaving him under it.</p>",

    "31": "<p><strong>archēgon kai sōtēra</strong> (<em>archēgon kai sōtēra</em>, 'Pioneer and Savior'): the <em>archēgos</em> Christology continues from 3:15. A <em>sōtēr</em> (savior) in Hellenistic political usage was typically a king or general who delivered a city from enemies; Luke applies it to Jesus as the deliverer from sin and death. The pairing — Pioneer who goes first, Savior who brings others through — is Luke's comprehensive summary of Christ's redemptive work. <strong>metanoia</strong> and <strong>aphesis</strong> ('repentance' and 'forgiveness') are the twin gifts his exaltation makes available.</p>",

    "32": "<p><strong>martyres</strong> again (cf. 1:8, 22; 2:32; 3:15; 4:33; 5:32): Luke's accumulating use of the witness-vocabulary emphasizes that apostolic testimony is grounded in personal encounter, not theological speculation. The Spirit's co-witness (<em>kai to Pneuma to Hagion ho edōken ho theos tois peitharchousin autō</em>) is significant: the Spirit testifies alongside the human witnesses, making the testimony doubly grounded — in eyewitness experience and in ongoing divine confirmation.</p>",

    "33": "<p><strong>dieprionto</strong> (<em>dieprionto</em>, 'they were cut to the quick/sawn asunder'): the violent metaphor — literally 'to be sawn through' — describes the council's furious reaction. The word appears again in 7:54 at Stephen's speech. The council's rage stands in sharp contrast to the crowd's receptive fear (v.11) and prepares for Gamaliel's moderating intervention.</p>",

    "34": "<p><strong>Gamaliel</strong>: identified as a Pharisee and <em>nomodidaskalos</em> (teacher of the law), honored by all the people. The Gamaliel of Acts is almost certainly the Gamaliel I mentioned in later rabbinic tradition as a leading sage; Paul identifies himself as trained at Gamaliel's feet (22:3). Luke presents the Pharisees and Sadducees as divided in their response to the apostles — the Sadducees drive the persecution, while this leading Pharisee advocates restraint.</p>",

    "35": "<p>Gamaliel's speech addresses the Sanhedrin with the formal address <em>andres Israēlitai</em> ('men of Israel') and immediately counsels caution (<em>prosechete heautois</em>, 'take care for yourselves'). His appeal is to pragmatic historical precedent rather than theological principle — he does not assess whether the apostles' claims are true but whether suppression is strategically wise. Luke's inclusion of this speech is not a straightforward endorsement of Gamaliel's reasoning but a narrative device showing that even the council's own members could not unify against the apostles.</p>",

    "36": "<p>The Theudas reference creates a famous historical difficulty: Josephus mentions a Theudas who led a movement around AD 44-46, after the events of Acts 5. Either Luke's dating is imprecise, there were multiple figures named Theudas, or Luke has inverted the chronological sequence in constructing Gamaliel's speech. The historical problem does not undermine Luke's theological point but is worth noting for honest engagement with the text.</p>",

    "37": "<p>Judas the Galilean led a tax revolt at the census of AD 6 (Josephus, <em>Antiquities</em> 18.1.1), establishing the anti-Roman Zealot tradition. Gamaliel's point — that both movements dissolved when their leaders died — is historically accurate for Judas. His argument has the form of an analogy from recent history: if this is of human origin, it will follow the same pattern; if from God, you cannot stop it.</p>",

    "38": "<p><strong>aphete autous</strong> ('leave them alone'): Gamaliel's counsel is restraint, not openness. His logic — <em>ei estin ex anthrōpōn hē boulē hautē ē to ergon touto</em> ('if this plan or work is from men') — is pragmatic probability-assessment, not theological discernment. The argument works as a rhetorical check on the council's anger without requiring Gamaliel to assess the apostles' claims. Luke does not endorse Gamaliel's methodology (it would apply equally to any movement that survived) but uses it to show that even the council's own traditions argued against violent suppression.</p>",

    "39": "<p><strong>mēpote kai theomachoi heurethēte</strong> ('you might even be found fighting against God'): the <em>theomachos</em> (God-fighter) was a category of hubris in both Hellenistic and Jewish thought — the human who presumes to oppose divine action. Gamaliel's warning is the sharpest edge of his argument: if this is God's work, suppression is not merely futile but blasphemous. The council cannot be certain which it is; prudence therefore counsels restraint. The irony for Luke's reader is that it <em>is</em> God's work, making the council's subsequent flogging (v.40) a confirmed case of theomachic overreach.</p>",

    "40": "<p><strong>mastigōsantes</strong> ('having flogged them'): the Sanhedrin did not follow Gamaliel's counsel completely — they flogged the apostles before releasing them. The Jewish judicial flogging was Deut 25:2-3's thirty-nine stripes (Paul refers to receiving this five times, 2 Cor 11:24). The flogging was intended as both punishment and deterrent; its actual effect (v.41) is the inverse of what was intended.</p>",

    "41": "<p><strong>chairontes</strong> ('rejoicing'): the apostles' response to flogging is characterized by Luke as genuine joy, not stoic endurance. The grounds — <em>hoti katēxiōthēsan atimasthēnai hyper tou onomatos</em> ('that they were counted worthy to suffer dishonor for the name') — invert the normal honor-shame calculus. In a society where public shame was devastating, the apostles experience their dishonor as a form of honor — sharing in their Lord's suffering, as Jesus had promised (Luke 6:22-23; 21:12-13). The beatitude is being enacted.</p>",

    "42": "<p><strong>kath' hēmeran</strong> ('day by day') + <strong>kat' oikon</strong> ('from house to house') + <strong>en tō hierō</strong> ('in the temple'): Luke's closing summary describes the rhythm of apostolic ministry — daily, in both public space (temple) and private space (homes), never stopping (<em>ouk epaūonto</em>). The word 'teaching' (<em>didaskontes</em>) and 'proclaiming the good news' (<em>euangelizomenoi</em>) are paired; both catechesis of believers and evangelism of outsiders are continuous. The pattern will be disrupted only by the Hellenist controversy of ch.6.</p>"
  },

  "6": {
    "1": "<p><strong>Hellēnistai pros tous Hebraious</strong> ('Hellenists against the Hebrews'): the two groups are Greek-speaking diaspora Jews who had settled in Jerusalem versus Aramaic-speaking native Palestinian Jews. Both were Christians; the division reflects the sociolinguistic fault line within Second Temple Judaism rather than any ethnic distinction. The complaint about the daily food distribution (<em>en tē diakonia tē kathēmerinē</em>) identifies the church's first internal administrative failure — not a theological dispute but a logistical inequity with demographic dimensions.</p>",

    "2": "<p><strong>kataleipsantas ton logon tou theou</strong> ('leaving/neglecting the word of God'): the Twelve's reasoning prioritizes the ministry of the word over administrative management. <strong>diakonein trapezais</strong> ('serve tables'): <em>diakonia</em> (service/ministry) will be applied both to the Twelve's ministry of the word (v.4) and to the Seven's table service — Luke does not demean the Seven's work but establishes a differentiation of function. Both are forms of <em>diakonia</em>.</p>",

    "3": "<p><strong>martyroumenous</strong> (<em>martyroumenous</em>, 'well-attested/of good reputation'): the qualifications for the Seven — good reputation, Spirit-filling, wisdom — are the same qualities required for leadership throughout the Pastoral Epistles and point to the proto-diaconal office. <em>Plēreis pneumatos hagiou kai sophias</em> ('full of the Holy Spirit and wisdom'): the pairing of Spirit and wisdom reflects the OT endowment of the craftsmen of the Tabernacle (Exod 31:3; 35:31) and the Servant (Isa 11:2), marking these men as set apart for divine service.</p>",

    "4": "<p><strong>proskarterēsomen</strong> (<em>proskarterēsomen</em>, 'we will devote ourselves'): the same verb used for the community's prayer in 1:14 and for their adherence to the apostles' teaching in 2:42. The Twelve's commitment to prayer and the word-ministry is not a demotion of administrative work but a recognition of their specific calling. The word-and-prayer combination is the apostolic core from which everything else flows.</p>",

    "5": "<p><strong>Stephanos, anēr plērēs pisteōs kai pneumatos hagiou</strong> ('Stephen, a man full of faith and the Holy Spirit'): Luke's introduction of Stephen singles him out from the Seven with the same Spirit-fullness language that will characterize his subsequent ministry (v.8) and his death (7:55). The Seven's names are all Greek (<em>Nikolaos</em> alone is explicitly identified as a proselyte), suggesting that the seven chosen to serve the Hellenist widows were themselves Hellenist Jews — an administratively elegant solution.</p>",

    "6": "<p><strong>proseuxamenoi epethēkan autois tas cheiras</strong> ('having prayed they laid their hands on them'): the commissioning gesture combines prayer and handlaying. In the OT, handlaying transferred authority and blessing (Num 27:18-23, Joshua's commissioning; Deut 34:9, the Spirit of wisdom transferred to Joshua). Here it is not ordination in a later technical sense but a formal recognition and authorization of the Seven's specific task. The same gesture in 13:3 will commission Paul and Barnabas for the Gentile mission.</p>",

    "7": "<p><strong>ho logos tou theou ēuxanen</strong> ('the word of God kept growing'): the third of Luke's Acts progress reports (2:47; 4:4; 5:14; 6:7 — and more to follow). Each summary follows resolution of a crisis: the Ananias crisis resolved → growth; the Sanhedrin crisis resolved → growth; the Hellenist administrative crisis resolved → growth. <strong>polys te ochlos tōn hiereōn hypēkouon tē pistei</strong> ('a large number of priests were obedient to the faith'): this detail is striking — members of the temple establishment, the class most implicated in Jesus's crucifixion, are being converted. The gospel is reaching the center of official Judaism.</p>",

    "8": "<p><strong>plērēs charitos kai dynameōs</strong> ('full of grace and power'): Stephen's characterization shifts from administrative appointment to apostolic-level ministry — <em>sēmeia kai terata megala</em> ('great signs and wonders'). The same vocabulary used for the apostles (2:43; 5:12) is now applied to one of the Seven. Luke signals that the Spirit's work through the Hellenist leaders extends beyond the Twelve, preparing for the geographic expansion of the mission through Stephen's speech and Philip's ministry in ch.8.</p>",

    "9": "<p><strong>Synagōgē Libertinōn</strong> ('Synagogue of the Freedmen'): likely descendants of Jews taken to Rome as slaves by Pompey in 63 BC and subsequently freed, who maintained their own synagogue in Jerusalem. The listing of multiple groups — Cyrenians, Alexandrians, Cilicians, Asians — indicates that Stephen's opponents were Diaspora Jews who had returned to Jerusalem, many of them Greek-speakers like Stephen himself. The opposition comes from within the Hellenist community, not from native Palestinians.</p>",

    "10": "<p><strong>ouk ischyon antistēnai tē sophia kai tō pneumati</strong> ('they could not withstand the wisdom and the Spirit'): the opposition's inability to overcome Stephen's arguments fulfills Jesus's promise of Luke 21:15 ('I will give you a mouth and wisdom which none of your adversaries will be able to withstand or contradict'). <em>Sophia</em> (wisdom) and <em>pneuma</em> (Spirit) are the gifts that cannot be matched by the synagogue debaters' conventional learning.</p>",

    "11": "<p><strong>blasphēmous logous eis Mōusēn kai ton theon</strong> ('blasphemous words against Moses and God'): the charge of blasphemy — the technical capital offence under Jewish law — is introduced through suborned false witnesses (<em>hypebalan andras</em>, 'they secretly persuaded men'). Luke's language explicitly marks the testimony as false (<em>martyras pseudeis</em>, v.13), paralleling Jesus's trial (Luke 22:66-71). Stephen's situation replicates his Lord's: falsely accused of blasphemy before the same body.</p>",

    "12": "<p><strong>kinēsantes ton laon kai tous presbyterous kai tous grammateis</strong> ('stirring up the people and the elders and the scribes'): the progression is significant — the opposition cannot refute Stephen's arguments (v.10), so they resort to crowd agitation and official mobilization. The <em>laos</em> (people) who served as protection for the apostles in chs.4-5 is now being turned against Stephen. The populace is more volatile than the Sanhedrin's institutional opposition.</p>",

    "13": "<p><strong>martyras pseudeis</strong> ('false witnesses'): Luke's explicit identification of the witnesses as false contrasts with the apostolic <em>martyria</em> (true witness). The parallel to Jesus's trial is precise: false witnesses at the Sanhedrin, the charge of threatening the temple, the high priest's questioning. Luke is constructing a deliberate parallel between Stephen's passion and Jesus's passion, preparing the reader to understand Stephen as the proto-martyr who follows his Lord's pattern fully.</p>",

    "14": "<p><strong>katalysei ton topon touton</strong> ('will destroy this place'): the charge echoes the accusation at Jesus's trial (Mark 14:58; Matt 26:61). Stephen's actual theology of the temple — worked out in 7:44-50 — argues not for destruction but for transcendence: the temple was always a pointer to something greater that has now arrived. The accusation distorts his position. <strong>allaxei ta ethē</strong> ('will change the customs'): this is the deeper charge — that Jesus changes what Moses established — which ch.7 addresses as Torah correctly understood pointing to Christ.</p>",

    "15": "<p><strong>hōsei prosōpon angelou</strong> ('like the face of an angel'): Stephen's transfigured appearance before the Sanhedrin prolepticly manifests the glory he will see in v.7:55-56. In the OT, the face-of-an-angel motif marks someone as a divine messenger in the presence of God (cf. Dan 3:25, 'the fourth man is like a son of the gods'; Judg 13:6, 'the man of God had the face of an angel'). The Sanhedrin is not simply judging a man; they are, unknowingly, facing a man who is standing at the threshold of the divine glory he is about to fully enter.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'acts')
    merge_comm(existing, ORIGINAL)
    save_comm('mkt-original', 'acts', existing)
    for ch in ['4', '5', '6']:
        count = len(existing.get(ch, {}))
        print(f'  ch{ch}: {count} entries')

if __name__ == '__main__':
    main()
